import { useLocation } from "react-router-dom"
import "./profile.css"
export const Profile = () => {
    const location = useLocation()
  return (
    <div className="profile">
        <h1>allUsers</h1>
        {location.state[0].map((user)=> {
            <p>{user.userName}</p>
        })}
        
    </div>
  )
}
